import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { createFallbackFloorContentProvider } from "../../harness/fallback-provider.js";
import type { TraceWriter } from "../../harness/trace/recorder.js";
import { personaPolicies } from "./policies/index.js";
import { runPersonaBot } from "./driver.js";
import {
  PERSONA_BANK_MAX_TURNS,
  PERSONA_BANK_SEEDS,
  type PersonaBankSeed,
  type PersonaName,
} from "./types.js";

const repoRoot = fileURLToPath(new URL("../../..", import.meta.url));
export const EVAL_BANK_DIR = join(repoRoot, "tests/eval-bank");

const memoryTraceWriter = (path: string): TraceWriter => ({
  path,
  writeHeader: () => {},
  appendTurn: () => {},
});

export type PersonaBankFixture = {
  readonly persona: PersonaName;
  readonly seed: PersonaBankSeed;
  readonly relativePath: string;
  readonly absolutePath: string;
};

export const personaBankFixturePath = (
  persona: PersonaName,
  seed: PersonaBankSeed,
): string => join(EVAL_BANK_DIR, `${persona}-${seed}.ndjson`);

export const generatePersonaBankFixtures = (): readonly PersonaBankFixture[] => {
  mkdirSync(EVAL_BANK_DIR, { recursive: true });
  const fixtures: PersonaBankFixture[] = [];

  for (const persona of personaPolicies) {
    for (const seed of PERSONA_BANK_SEEDS) {
      const absolutePath = personaBankFixturePath(persona.name, seed);
      const run = runPersonaBot(
        persona,
        seed,
        createFallbackFloorContentProvider(),
        PERSONA_BANK_MAX_TURNS,
        {
          runId: `eval-bank-${persona.name}-${seed}`,
          writer: memoryTraceWriter(`memory://${persona.name}/${seed}.ndjson`),
        },
      );
      writeFileSync(absolutePath, run.trace.content, "utf8");
      fixtures.push({
        persona: persona.name,
        seed,
        relativePath: join("tests/eval-bank", `${persona.name}-${seed}.ndjson`),
        absolutePath,
      });
    }
  }

  return fixtures;
};

export const readPersonaBankFixture = (
  persona: PersonaName,
  seed: PersonaBankSeed,
): string => readFileSync(personaBankFixturePath(persona, seed), "utf8");

export const writePersonaBankFixture = (
  persona: PersonaName,
  seed: PersonaBankSeed,
  content: string,
): void => {
  const path = personaBankFixturePath(persona, seed);
  mkdirSync(dirname(path), { recursive: true });
  writeFileSync(path, content, "utf8");
};

export * from "./types.js";
export * from "./policies/index.js";
export * from "./driver.js";
export * from "./bank.js";
export * from "./signatures.js";

import {
  HARD_CANON_BLOCK,
  buildPersonaBlock,
  buildTaskBlock,
} from "./blocks.js";
import type { AssemblePromptInput } from "./types.js";
import { PROMPT_MAX_CHAR_LENGTH } from "./types.js";

export const assemblePrompt = (input: AssemblePromptInput): string => {
  const sections = [
    HARD_CANON_BLOCK,
    buildPersonaBlock(input.band),
    input.traceFacts.textBlock,
  ];

  if (input.memoryBlock && input.memoryBlock.trim().length > 0) {
    sections.push(`CROSS-RUN MEMORY\n${input.memoryBlock.trim()}`);
  }

  sections.push(
    buildTaskBlock({
      band: input.band,
      depth: input.depth,
      config: input.config,
      bounds: input.bounds,
      seed: input.runContext.seed,
      playerSummary: input.traceFacts.textBlock,
    }),
  );

  const prompt = sections.join("\n\n");

  if (prompt.length > PROMPT_MAX_CHAR_LENGTH) {
    throw new Error(
      `assembled prompt exceeds budget (${prompt.length} > ${PROMPT_MAX_CHAR_LENGTH} chars)`,
    );
  }

  return prompt;
};

export const promptCharLength = (prompt: string): number => prompt.length;

import { config } from "../../config/index.js";
import {
  listFloors,
  loadGenerationChain,
  type ArtifactReadOptions,
  type GenerationAttemptRecord,
  type GenerationRecord,
} from "../../harness/artifacts/index.js";
import type { DepthBand } from "../../schemas/entities/index.js";
import type { Gate2ReasonCode, Gate2Report } from "../../gauntlet/gate2/judge.js";

export const EVAL_METRIC_VERSION = "phase-40b-core-v1" as const;

export type EvalTokenUsage = {
  readonly inputTokens: number | null;
  readonly outputTokens: number | null;
  readonly totalTokens: number | null;
};

type TokenUsageLike = {
  readonly inputTokens?: number | null;
  readonly outputTokens?: number | null;
  readonly totalTokens?: number | null;
};

export type EvalTokenStats = {
  readonly recordCountWithTokens: number;
  readonly totals: EvalTokenUsage | null;
  readonly averagePerRecordWithTokens: EvalTokenUsage | null;
};

export type EvalRate = {
  readonly count: number;
  readonly passed: number;
  readonly percent: number;
};

export type EvalLatencyStats = {
  readonly count: number;
  readonly min: number;
  readonly p50: number;
  readonly avg: number;
  readonly max: number;
};

export type EvalRepairDistribution = {
  readonly zero: number;
  readonly one: number;
  readonly two: number;
  readonly threeOrMore: number;
  readonly byRepairCount: readonly EvalRepairBucket[];
};

export type EvalRepairBucket = {
  readonly repairCount: number;
  readonly count: number;
};

export type EvalAdvisoryFlags = {
  readonly hpRetentionRecorded: boolean;
  readonly hpRetentionAdvisory: boolean;
  readonly hpRetentionPassed: boolean | null;
  readonly advisoryCodes: readonly Gate2ReasonCode[];
  readonly failedAdvisoryCodes: readonly Gate2ReasonCode[];
};

export type EvalBandAccuracy = {
  readonly band: DepthBand;
  readonly clearRatePercent: number;
  readonly clearRateTargetPercent: number;
  readonly clearRateMet: boolean;
  readonly medianHpRetentionPercent: number;
  readonly medianHpRetentionTargetPercent: {
    readonly min: number;
    readonly max: number;
  };
  readonly hpRetentionInBand: boolean;
  readonly accurate: boolean;
};

export type EvalGate2Score = {
  readonly recorded: boolean;
  readonly passed: boolean;
  readonly blockingCodes: readonly Gate2ReasonCode[];
};

export type EvalGenerationScore = {
  readonly runId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly attemptCount: number;
  readonly validity: boolean;
  readonly solvability: boolean;
  readonly servedWithoutFallback: boolean;
  readonly repairCount: number;
  readonly fallback: boolean;
  readonly latencyMs: number;
  readonly tokens: EvalTokenUsage | null;
  readonly gate2: EvalGate2Score;
  readonly advisoryFlags: EvalAdvisoryFlags;
  readonly bandAccuracy: EvalBandAccuracy | null;
};

export type EvalRates = {
  readonly validity: EvalRate;
  readonly solvability: EvalRate;
  readonly servedWithoutFallback: EvalRate;
  readonly fallback: EvalRate;
  readonly bandAccuracy: EvalRate;
};

export type EvalBandBreakdown = {
  readonly band: DepthBand;
  readonly count: number;
  readonly rates: EvalRates;
  readonly latencyMs: EvalLatencyStats;
  readonly repairDistribution: EvalRepairDistribution;
  readonly tokens: EvalTokenStats;
};

export type EvalComparabilityFields = {
  readonly baselineId?: string;
  readonly candidateId?: string;
  readonly segmentId?: string;
};

export type EvalScores = {
  readonly recordType: "eval-scores";
  readonly metricVersion: typeof EVAL_METRIC_VERSION;
  readonly recordCount: number;
  readonly generations: readonly EvalGenerationScore[];
  readonly summary: {
    readonly rates: EvalRates;
    readonly latencyMs: EvalLatencyStats;
    readonly repairDistribution: EvalRepairDistribution;
    readonly tokens: EvalTokenStats;
    readonly byBand: Readonly<Record<DepthBand, EvalBandBreakdown>>;
  };
  readonly comparability?: EvalComparabilityFields;
};

export type ScoreGenerationRecordsOptions = {
  readonly comparability?: EvalComparabilityFields;
};

export type ScoreRunGenerationArtifactsOptions = ArtifactReadOptions &
  ScoreGenerationRecordsOptions;

const DEPTH_BANDS: readonly DepthBand[] = ["shallows", "middle", "lowest"];

export const scoreGenerationRecord = (
  record: GenerationRecord,
): EvalGenerationScore => {
  const firstAttempt = record.attempts[0];
  const gate2 = gate2ReportForRecord(record);
  const band = bandForDepth(record.depth);
  const tokens = sumTokens(record.attempts);
  const gate2Score = scoreGate2(gate2);

  return {
    runId: record.runId,
    depth: record.depth,
    band,
    attemptCount: record.attempts.length,
    validity:
      firstAttempt?.gateReports?.gate0?.pass === true &&
      firstAttempt.gateReports.gate1?.pass === true,
    solvability: gate2Score.passed,
    servedWithoutFallback: record.outcome.kind === "manifest",
    repairCount: Math.max(0, record.attempts.length - 1),
    fallback: record.outcome.kind === "fallback",
    latencyMs: sumLatencyMs(record.attempts),
    tokens,
    gate2: gate2Score,
    advisoryFlags: scoreAdvisoryFlags(gate2),
    bandAccuracy: scoreBandAccuracy(band, gate2),
  };
};

export const scoreGenerationRecords = (
  records: readonly GenerationRecord[],
  options: ScoreGenerationRecordsOptions = {},
): EvalScores => {
  const generations = records.map(scoreGenerationRecord);

  return {
    recordType: "eval-scores",
    metricVersion: EVAL_METRIC_VERSION,
    recordCount: generations.length,
    generations,
    summary: {
      rates: ratesFor(generations),
      latencyMs: latencyStats(generations.map((score) => score.latencyMs)),
      repairDistribution: repairDistribution(generations),
      tokens: tokenStats(generations),
      byBand: bandBreakdowns(generations),
    },
    ...(options.comparability === undefined
      ? {}
      : { comparability: options.comparability }),
  };
};

export const loadGenerationRecordsForRun = (
  runId: string,
  options: ArtifactReadOptions = {},
): readonly GenerationRecord[] =>
  listFloors(runId, options).map((floor) =>
    loadGenerationChain(runId, floor.depth, options),
  );

export const scoreRunGenerationArtifacts = (
  runId: string,
  options: ScoreRunGenerationArtifactsOptions = {},
): EvalScores =>
  scoreGenerationRecords(loadGenerationRecordsForRun(runId, options), {
    ...(options.comparability === undefined
      ? {}
      : { comparability: options.comparability }),
  });

const gate2ReportForRecord = (
  record: GenerationRecord,
): Gate2Report | undefined => {
  const scoredAttempt = attemptForRecordOutcome(record);

  if (scoredAttempt?.gateReports?.gate2 !== undefined) {
    return scoredAttempt.gateReports.gate2;
  }

  return last(
    record.attempts
      .map((attempt) => attempt.gateReports?.gate2)
      .filter((report): report is Gate2Report => report !== undefined),
  );
};

const attemptForRecordOutcome = (
  record: GenerationRecord,
): GenerationAttemptRecord | undefined => {
  if (record.outcome.kind === "manifest") {
    const servedManifestPath = record.outcome.manifestPath;
    const servedAttempt = record.attempts.find(
      (attempt) => attempt.provider.manifestPath === servedManifestPath,
    );

    if (servedAttempt !== undefined) {
      return servedAttempt;
    }

    return last(record.attempts.filter((attempt) => attempt.provider.ok));
  }

  return last(record.attempts);
};

const scoreGate2 = (report: Gate2Report | undefined): EvalGate2Score => {
  if (report === undefined) {
    return {
      recorded: false,
      passed: false,
      blockingCodes: [],
    };
  }

  return {
    recorded: true,
    passed: report.pass,
    blockingCodes: report.verdict.codes,
  };
};

const scoreAdvisoryFlags = (
  report: Gate2Report | undefined,
): EvalAdvisoryFlags => {
  const checks = report?.checks ?? [];
  const advisoryChecks = checks.filter((check) => check.advisory === true);
  const hpRetention = checks.find((check) => check.code === "G2_HP_RETENTION");

  return {
    hpRetentionRecorded: hpRetention !== undefined,
    hpRetentionAdvisory: hpRetention?.advisory === true,
    hpRetentionPassed: hpRetention?.pass ?? null,
    advisoryCodes: advisoryChecks.map((check) => check.code),
    failedAdvisoryCodes: advisoryChecks
      .filter((check) => !check.pass)
      .map((check) => check.code),
  };
};

const scoreBandAccuracy = (
  band: DepthBand,
  report: Gate2Report | undefined,
): EvalBandAccuracy | null => {
  if (report === undefined) {
    return null;
  }

  const target = config.difficultyGate.thresholdsByBand[band];
  const clearRatePercent = report.metrics.clearRatePercent;
  const medianHpRetentionPercent = report.metrics.medianHpRetentionPercent;
  const clearRateMet = clearRatePercent >= target.clearRateMinPercent;
  const hpRetentionInBand =
    medianHpRetentionPercent >= target.medianHpRetentionPercent.min &&
    medianHpRetentionPercent <= target.medianHpRetentionPercent.max;

  return {
    band,
    clearRatePercent,
    clearRateTargetPercent: target.clearRateMinPercent,
    clearRateMet,
    medianHpRetentionPercent,
    medianHpRetentionTargetPercent: {
      min: target.medianHpRetentionPercent.min,
      max: target.medianHpRetentionPercent.max,
    },
    hpRetentionInBand,
    accurate: clearRateMet && hpRetentionInBand,
  };
};

import { config } from "../../config/index.js";
import type { ParsedTrace } from "../../harness/replay/types.js";
import type { DepthBand } from "../../schemas/entities/index.js";

export type BehavioralFacts = {
  readonly combatEngagementRate: number;
  readonly fightsPicked: number;
  readonly fightsAvoided: number;
  readonly retreatCount: number;
  readonly retreatFrequency: number;
  readonly itemPickups: number;
  readonly itemUses: number;
  readonly itemUsesByCategory: Readonly<Record<string, number>>;
  readonly hoardingSignal: number;
  readonly npcTalksInitiated: number;
  readonly explorationRatio: number;
  readonly cellsVisited: number;
  readonly floorCellsEstimate: number;
  readonly closeCallCount: number;
  readonly killsByEnemyType: Readonly<Record<string, number>>;
  readonly questAccepted: number;
  readonly questRefused: number;
  readonly questCompleted: number;
  readonly totalTurns: number;
};

export type TraceSummaryResult = {
  readonly facts: BehavioralFacts;
  readonly textBlock: string;
};

const ITEM_USE_EVENTS = new Set([
  "item_consumed",
  "item_triggered",
  "item_charge_used",
]);

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === "object" && !Array.isArray(value);

const readString = (record: Record<string, unknown>, key: string): string | null => {
  const value = record[key];
  return typeof value === "string" ? value : null;
};

const readNumber = (record: Record<string, unknown>, key: string): number | null => {
  const value = record[key];
  return typeof value === "number" && Number.isFinite(value) ? value : null;
};

const cellKey = (x: number, y: number): string => `${x},${y}`;

const categoryFromDefinitionId = (definitionId: string): string => {
  const prefix = definitionId.split("-")[0] ?? definitionId;
  return prefix.length > 0 ? prefix : "unknown";
};

const floorCellsForBand = (band: DepthBand): number => {
  const geometry = config.runStructure.floorGeometry[band];
  return geometry.grid.width * geometry.grid.height;
};

const capWords = (text: string, maxWords: number): string => {
  const words = text.trim().split(/\s+/);
  if (words.length <= maxWords) {
    return text.trim();
  }

  return `${words.slice(0, maxWords).join(" ")}…`;
};

export const summarizeTrace = (
  trace: ParsedTrace,
  options?: { readonly band?: DepthBand },
): TraceSummaryResult => {
  const band = options?.band ?? "shallows";
  const floorCellsEstimate = floorCellsForBand(band);
  const visitedCells = new Set<string>();
  const itemUsesByCategory: Record<string, number> = {};
  const killsByEnemyType: Record<string, number> = {};
  const enemyDefinitionById = new Map<string, string>();

  let fightsPicked = 0;
  let fightsAvoided = 0;
  let retreatCount = 0;
  let itemPickups = 0;
  let itemUses = 0;
  let npcTalksInitiated = 0;
  let questAccepted = 0;
  let questRefused = 0;
  let questCompleted = 0;
  let closeCallCount = 0;

  let playerMaxHp: number = config.playerCharacter.stats.hp.start;
  let playerHp: number = playerMaxHp;
  let recentlyDamaged = false;
  let enemyPresentThisTurn = false;

  for (const turn of trace.turns) {
    const action = turn.action as Record<string, unknown>;
    const actionKind = readString(action, "kind");

    if (actionKind === "attack") {
      fightsPicked += 1;
      recentlyDamaged = false;
    } else if (actionKind === "move" && recentlyDamaged) {
      retreatCount += 1;
      recentlyDamaged = false;
    } else if (actionKind === "talk") {
      npcTalksInitiated += 1;
    } else if (actionKind === "pickup") {
      // pickup counted from events
    }

    enemyPresentThisTurn = false;

    for (const event of turn.events) {
      const rawData = event.data;
      if (!isRecord(rawData)) {
        continue;
      }
      const data: Record<string, unknown> = rawData;

      switch (event.type) {
        case "moved": {
          if (readString(data, "actorId") === "player") {
            const toValue = data["to"];
            const to = isRecord(toValue) ? toValue : null;
            const x = to ? readNumber(to, "x") : null;
            const y = to ? readNumber(to, "y") : null;
            if (x !== null && y !== null) {
              visitedCells.add(cellKey(x, y));
            }
          }
          break;
        }
        case "attack_hit": {
          const defenderId = readString(data, "defenderId");
          if (defenderId === "player") {
            const hpAfter = readNumber(data, "defenderHpAfter");
            if (hpAfter !== null) {
              playerHp = hpAfter;
              if (playerHp / playerMaxHp < 0.25) {
                closeCallCount += 1;
              }
            }
            recentlyDamaged = true;
          } else if (readString(data, "actorId") === "player") {
            const targetId = defenderId;
            if (targetId) {
              enemyDefinitionById.set(targetId, targetId);
            }
          }
          break;
        }
        case "entity_died": {
          if (readString(data, "kind") === "enemy") {
            const entityId = readString(data, "entityId") ?? "enemy";
            const label = enemyDefinitionById.get(entityId) ?? entityId;
            killsByEnemyType[label] = (killsByEnemyType[label] ?? 0) + 1;
          }
          break;
        }
        case "item_picked_up": {
          itemPickups += 1;
          const definitionId = readString(data, "definitionId");
          if (definitionId) {
            const category = categoryFromDefinitionId(definitionId);
            itemUsesByCategory[`pickup:${category}`] =
              (itemUsesByCategory[`pickup:${category}`] ?? 0) + 1;
          }
          break;
        }
        case "item_consumed":
        case "item_triggered":
        case "item_charge_used": {
          if (ITEM_USE_EVENTS.has(event.type)) {
            itemUses += 1;
            const definitionId = readString(data, "definitionId") ?? "unknown";
            const category = categoryFromDefinitionId(definitionId);
            itemUsesByCategory[category] = (itemUsesByCategory[category] ?? 0) + 1;
          }
          break;
        }
        case "level_up": {
          if (readString(data, "actorId") === "player") {
            const maxHpAfter = readNumber(data, "maxHpAfter");
            const currentHpAfter = readNumber(data, "currentHpAfter");
            if (maxHpAfter !== null) {
              playerMaxHp = maxHpAfter;
            }
            if (currentHpAfter !== null) {
              playerHp = currentHpAfter;
              if (playerHp / playerMaxHp < 0.25) {
                closeCallCount += 1;
              }
            }
          }
          break;
        }
        case "quest_accepted":
          questAccepted += 1;
          break;
        case "quest_refused":
          questRefused += 1;
          break;
        case "quest_completed":
          questCompleted += 1;
          break;
        case "talk_intent":
        case "dialogue_opened":
          npcTalksInitiated += 1;
          break;
        case "actor_turn": {
          const actorId = readString(data, "actorId");
          if (actorId?.startsWith("enemy")) {
            enemyPresentThisTurn = true;
          }
          break;
        }
        default:
          break;
      }
    }

    if (enemyPresentThisTurn && actionKind === "move") {
      fightsAvoided += 1;
    }
  }

  const totalTurns = trace.turns.length;
  const combatDenominator = Math.max(1, fightsPicked + fightsAvoided);
  const combatEngagementRate = fightsPicked / combatDenominator;
  const hoardingSignal = itemPickups / Math.max(1, itemUses);
  const explorationRatio =
    visitedCells.size / Math.max(1, floorCellsEstimate);
  const retreatFrequency = retreatCount / Math.max(1, totalTurns);

  const facts: BehavioralFacts = {
    combatEngagementRate,
    fightsPicked,
    fightsAvoided,
    retreatCount,
    retreatFrequency,
    itemPickups,
    itemUses,
    itemUsesByCategory,
    hoardingSignal,
    npcTalksInitiated,
    explorationRatio,
    cellsVisited: visitedCells.size,
    floorCellsEstimate,
    closeCallCount,
    killsByEnemyType,
    questAccepted,
    questRefused,
    questCompleted,
    totalTurns,
  };

import type { RunAction } from "../../engine/run/loop.js";
import type { BotStateView } from "../../harness/bots/types.js";
import type { BehavioralFacts } from "../../director/prompt/summarize.js";

export type PersonaName =
  | "hoarder"
  | "pacifist"
  | "speedrunner"
  | "completionist"
  | "chaos";

export type PersonaPolicy = {
  readonly name: PersonaName;
  readonly description: string;
  /**
   * Behavioral signature: measurable facts the trace summarizer should recover
   * from committed bank fixtures for this persona.
   */
  readonly signatureComment: string;
  readonly decide: (view: BotStateView) => RunAction;
};

export type PersonaSignatureCheck = {
  readonly label: string;
  readonly pass: (facts: BehavioralFacts) => boolean;
};

export type PersonaSignatureProfile = {
  readonly name: PersonaName;
  readonly checks: readonly PersonaSignatureCheck[];
};

export const PERSONA_BANK_SEEDS = [
  "persona-bank-1",
  "persona-bank-2",
  "persona-bank-3",
] as const;

export type PersonaBankSeed = (typeof PERSONA_BANK_SEEDS)[number];

/** Modest turn cap keeps bank fixtures small and fast to summarize in tests. */
export const PERSONA_BANK_MAX_TURNS = 140;

import type { GameBounds, GameConfig } from "../../config/index.js";
import type { DepthBand } from "../../schemas/entities/index.js";
import type { TraceSummaryResult } from "./summarize.js";

export type RunContext = {
  readonly seed: string;
  readonly runId?: string;
};

export type AssemblePromptInput = {
  readonly band: DepthBand;
  readonly depth: number;
  readonly config: GameConfig;
  readonly bounds: GameBounds;
  readonly traceFacts: TraceSummaryResult;
  readonly memoryBlock?: string | null;
  readonly runContext: RunContext;
};

/** Character budget guard for assembled Director prompts (~8k tokens). */
export const PROMPT_MAX_CHAR_LENGTH = 32_000;

import { bounds, config as defaultConfig } from "../config/index.js";
import {
  materialize,
  type MaterializedFloor
} from "../director/apply/index.js";
import {
  type DirectorProvider,
  type GenerateManifestOptions,
  type ProviderFailureCode,
  type ProviderResult,
  failure
} from "../director/provider/index.js";
import type {
  FloorContent,
  FloorContentProvider
} from "../engine/run/index.js";
import { createFallbackFloorContentProvider } from "../harness/fallback-provider.js";
import {
  writeGenerationRecord,
  type GenerationAttemptInput,
  type GenerationRecord,
  type WriteGenerationRecordOptions
} from "../harness/artifacts/index.js";
import type { FloorManifest } from "../schemas/manifest.js";
import type { Gate2Check, Gate2Report } from "./gate2/judge.js";
import {
  defaultGate2Config,
  runGate2,
  type Gate2RunOptions
} from "./gate2/run.js";
import {
  failedChecks,
  runGate0,
  runGate1,
  type GateCheck,
  type GateReport,
  type Gate1Context
} from "./gates01/index.js";

export type RepairClock = () => string;

export type GenerateFloorContext = {
  readonly prompt: string;
  readonly provider: DirectorProvider;
  readonly runId: string;
  readonly depth: number;
  readonly seed: string;
  readonly modelId: string;
  readonly createdAt?: string;
  readonly recordedAt?: string;
  readonly now?: RepairClock;
  readonly gate1?: Gate1Context;
  readonly gate2?: Gate2RunOptions;
  readonly fallbackProvider?: FloorContentProvider;
  readonly artifacts?: WriteGenerationRecordOptions;
  readonly repairCap?: number;
  readonly providerOptions?: GenerateManifestOptions;
};

export type GenerateFloorResult = {
  readonly floor: MaterializedFloor | FloorContent;
  readonly record: GenerationRecord;
};

type EvaluatedAttempt =
  | {
      readonly kind: "manifest";
      readonly floor: MaterializedFloor;
      readonly gateReports: Required<GenerationAttemptInput["gateReports"]>;
    }
  | {
      readonly kind: "repairable";
      readonly gateReports: GenerationAttemptInput["gateReports"];
      readonly manifest?: FloorManifest;
    }
  | {
      readonly kind: "fallback";
      readonly gateReports?: GenerationAttemptInput["gateReports"];
    };

type RepairPromptInput = {
  readonly originalPrompt: string;
  readonly providerResult: ProviderResult;
  readonly gateReports: NonNullable<GenerationAttemptInput["gateReports"]>;
  readonly manifest?: FloorManifest;
};

type Gate2EvaluationResult =
  | {
      readonly kind: "pass";
      readonly floor: MaterializedFloor;
      readonly report: Gate2Report;
    }
  | {
      readonly kind: "fail";
      readonly report: Gate2Report;
    };

const IMMEDIATE_FALLBACK_PROVIDER_CODES = new Set<ProviderFailureCode>([
  "timeout",
  "process_error"
]);
const DEFAULT_ROOT_DIR = "runs";
const FRAGMENT_MAX_CHARS = 4_000;

export const generateFloor = async (
  ctx: GenerateFloorContext
): Promise<GenerateFloorResult> => {
  const repairCap = ctx.repairCap ?? bounds.gauntlet.repairRetriesMax;
  const attempts: GenerationAttemptInput[] = [];
  let prompt = ctx.prompt;
  let repairsUsed = 0;

  while (true) {
    const providerResult = await generateManifest(ctx.provider, prompt, {
      timeoutMs:
        ctx.providerOptions?.timeoutMs ??
        defaultConfig.director.manifestTimeoutMs
    });
    const evaluation = evaluateProviderResult(providerResult, ctx);
    attempts.push({
      prompt,
      providerResult,
      ...(evaluation.gateReports === undefined
        ? {}
        : { gateReports: evaluation.gateReports })
    });

    if (evaluation.kind === "manifest") {
      const record = writeRecord(ctx, attempts, {
        kind: "manifest",
        manifestPath: servedManifestPath(ctx, attempts.length - 1)
      });

      return {
        floor: evaluation.floor,
        record
      };
    }

    if (
      evaluation.kind === "fallback" ||
      repairsUsed >= repairCap ||
      evaluation.gateReports === undefined
    ) {
      return serveFallback(ctx, attempts);
    }

    prompt = buildRepairPrompt({
      originalPrompt: ctx.prompt,
      providerResult,
      gateReports: evaluation.gateReports,
      manifest: evaluation.manifest
    });
    repairsUsed += 1;
  }
};

export const buildRepairPrompt = ({
  originalPrompt,
  providerResult,
  gateReports,
  manifest
}: RepairPromptInput): string => {
  const failed = collectFailedChecks(gateReports);
  const checks = failed
    .map((check) => `- Gate ${check.gate} ${check.code}: ${check.detail}`)
    .join("\n");
  const fragments = offendingFragments(providerResult, manifest)
    .map((fragment) => `\`\`\`json\n${fragment}\n\`\`\``)
    .join("\n\n");

  return [
    originalPrompt,
    "",
    "Your previous output failed these checks:",
    checks.length === 0 ? "- No failed gate checks were recorded." : checks,
    "",
    "Fix only these checks; preserve valid content when possible.",
    "",
    "Offending JSON fragment(s):",
    fragments.length === 0
      ? "```json\n<empty provider output>\n```"
      : fragments,
    "",
    "Return the corrected complete JSON manifest only."
  ].join("\n");
};

const generateManifest = async (
  provider: DirectorProvider,
  prompt: string,
  options: GenerateManifestOptions
): Promise<ProviderResult> => {
  try {
    return await provider.generateManifest(prompt, options);
  } catch (error) {
    return failure(
      "process_error",
      error instanceof Error ? error.message : String(error),
      { latencyMs: 0, tokens: null }
    );
  }
};

const evaluateProviderResult = (
  providerResult: ProviderResult,
  ctx: GenerateFloorContext
): EvaluatedAttempt => {
  if (
    !providerResult.ok &&
    IMMEDIATE_FALLBACK_PROVIDER_CODES.has(providerResult.error.code)
  ) {
    return { kind: "fallback" };
  }

  const raw = providerResult.ok
    ? providerResult.raw
    : (providerResult.raw ?? "");
  const gate0 = runGate0(raw);
  if (!gate0.pass) {
    return {
      kind: "repairable",
      gateReports: { gate0 }
    };
  }

  if (!providerResult.ok) {
    return {
      kind: "fallback",
      gateReports: { gate0 }
    };
  }

  const gate1 = runGate1(providerResult.manifest, ctx.gate1);
  if (!gate1.pass) {
    return {
      kind: "repairable",
      gateReports: { gate0, gate1 },
      manifest: providerResult.manifest
    };
  }

  const gate2Evaluation = evaluateGate2(providerResult.manifest, ctx.gate2);
  const gateReports = {
    gate0,
    gate1,
    gate2: gate2Evaluation.report
  };

  if (gate2Evaluation.kind === "fail") {
    return {
      kind: "repairable",
      gateReports,
      manifest: providerResult.manifest
    };
  }

  return {
    kind: "manifest",

    kind: "manifest",
    floor: gate2Evaluation.floor,
    gateReports
  };
};

const evaluateGate2 = (
  manifest: FloorManifest,
  options: Gate2RunOptions = {}
): Gate2EvaluationResult => {
  let floor: MaterializedFloor;

  try {
    floor = materialize(manifest, manifest.params.seed, {
      ...(options.transformFloor === undefined
        ? {}
        : { transformFloor: options.transformFloor })
    }).floor;
  } catch (error) {
    return {
      kind: "fail",
      report: materializationFailureReport(manifest, options, error)
    };
  }

  try {
    const report = runGate2(manifest, options);

    if (!report.pass) {
      return {
        kind: "fail",
        report
      };
    }

    return {
      kind: "pass",
      floor,
      report
    };
  } catch (error) {
    return {
      kind: "fail",
      report: materializationFailureReport(manifest, options, error)
    };
  }
};

const materializationFailureReport = (
  manifest: FloorManifest,
  options: Gate2RunOptions,
  source: unknown
): Gate2Report => {
  const gateConfig = options.config ?? defaultGate2Config(manifest);
  const detail =
    source instanceof Error
      ? `candidate floor could not be materialized: ${source.message}`
      : `candidate floor could not be materialized: ${String(source)}`;
  const check: Gate2Check = {
    code: "G2_MATERIALIZATION",
    pass: false,
    detail
  };

  return {
    gate: 2,
    pass: false,
    verdict: {
      status: "reject",
      codes: ["G2_MATERIALIZATION"]
    },
    checks: [check],
    metrics: {
      totalRuns: 0,
      clearCount: 0,
      reachedStairsCount: 0,
      questCompletedCount: 0,
      deathCount: 0,
      clearRatePercent: 0,
      medianHpRetentionPercent: 0,
      minTurns: 0,
      maxTurns: 0
    },
    candidate: {
      seed: manifest.params.seed,
      stairsReachable: false,
      pathLength: null,
      hasThreatOnPath: false,
      placementDeviationCount: 0
    },
    ensemble: {
      policies: gateConfig.policies,
      seeds: gateConfig.seeds,
      maxTurns: gateConfig.maxTurns
    },
    elapsedMs: 0,
    wallClockBudgetMs: gateConfig.wallClockBudgetMs
  };
};

const collectFailedChecks = (
  gateReports: NonNullable<GenerationAttemptInput["gateReports"]>
): readonly {
  readonly gate: 0 | 1 | 2;
  readonly code: GateCheck["code"] | Gate2Check["code"];
  readonly detail: string;
}[] => [
  ...(gateReports.gate0 === undefined
    ? []
    : failedChecks(gateReports.gate0).map(withGate(gateReports.gate0))),
  ...(gateReports.gate1 === undefined
    ? []
    : failedChecks(gateReports.gate1).map(withGate(gateReports.gate1))),
  ...(gateReports.gate2 === undefined
    ? []
    : gateReports.gate2.checks
        .filter((check) => !check.pass)
        .map((check) => ({
          gate: 2 as const,
          code: check.code,
          detail: check.detail
        })))
];

const withGate =
  (report: GateReport) =>
  (
    check: GateCheck
  ): {
    readonly gate: 0 | 1;
    readonly code: GateCheck["code"];
    readonly detail: string;
  } => ({
    gate: report.gate,
    code: check.code,
    detail: check.detail
  });

const offendingFragments = (
  providerResult: ProviderResult,
  manifest: FloorManifest | undefined
): readonly string[] => {
  const raw = providerResult.ok ? providerResult.raw : providerResult.raw;
  if (raw !== undefined && raw.trim().length > 0) {
    return [truncateFragment(raw)];
  }

  if (manifest !== undefined) {
    return [truncateFragment(JSON.stringify(manifest, null, 2))];
  }

  return [];
};

const truncateFragment = (fragment: string): string =>
  fragment.length <= FRAGMENT_MAX_CHARS
    ? fragment
    : `${fragment.slice(0, FRAGMENT_MAX_CHARS)}\n...<truncated>`;

const serveFallback = (
  ctx: GenerateFloorContext,
  attempts: readonly GenerationAttemptInput[]
): GenerateFloorResult => {
  const fallbackProvider =
    ctx.fallbackProvider ?? createFallbackFloorContentProvider();
  const floor = fallbackProvider.getFloor(ctx.depth, ctx.seed);
  const record = writeRecord(ctx, attempts, {
    kind: "fallback",
    fallbackId: fallbackId(ctx.depth, floor)
  });

  return { floor, record };
};

const fallbackId = (depth: number, floor: FloorContent): string =>
  `fallback:old-stock:${floor.params.bandOrSize}-${depth}`;

const writeRecord = (
  ctx: GenerateFloorContext,
  attempts: readonly GenerationAttemptInput[],
  outcome: Parameters<typeof writeGenerationRecord>[0]["outcome"]
): GenerationRecord => {
  const createdAt = ctx.createdAt ?? ctx.now?.() ?? new Date().toISOString();
  const recordedAt = ctx.recordedAt ?? ctx.now?.() ?? createdAt;

  return writeGenerationRecord(
    {
      runId: ctx.runId,
      depth: ctx.depth,
      seed: ctx.seed,
      modelId: ctx.modelId,
      createdAt,
      recordedAt,
      attempts,
      outcome
    },
    ctx.artifacts
  );
};

const servedManifestPath = (
  ctx: GenerateFloorContext,
  attemptIndex: number
): string => {
  const rootDir = trimTrailingSlash(ctx.artifacts?.rootDir ?? DEFAULT_ROOT_DIR);
  return `${rootDir}/${ctx.runId}/floors/${ctx.depth}/attempts/${attemptIndex}/manifest.json`;
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

import type {
  ProviderError,
  ProviderResult,
  ProviderUsage,
} from "../../director/provider/types.js";
import type { GateReport } from "../../gauntlet/gates01/report.js";
import type { Gate2Report } from "../../gauntlet/gate2/judge.js";
