import { ENGINE_VERSION, PROTOCOL_VERSION } from "../../schemas/protocol.js";
import {
  nodeArtifactFsAdapter,
  trimTrailingSlash,
  type ArtifactFsAdapter,
} from "./fs.js";
import { hashPrompt } from "./hash.js";
import type {
  AttemptProviderSnapshot,
  FloorIndexEntry,
  GenerationAttemptInput,
  GenerationAttemptRecord,
  GenerationOutcome,
  GenerationOutcomeSummary,
  GenerationRecord,
  RunGenerationIndex,
  WriteGenerationRecordInput,
} from "./types.js";

export class GenerationRecordExistsError extends Error {
  readonly code = "GENERATION_RECORD_EXISTS" as const;

  constructor(runId: string, depth: number) {
    super(`generation record already exists for run ${runId} floor ${depth}`);
    this.name = "GenerationRecordExistsError";
  }
}

export type WriteGenerationRecordOptions = {
  readonly rootDir?: string;
  readonly fs?: ArtifactFsAdapter;
};

const GENERATION_RECORD_FILE = "generation.json";
const INDEX_FILE = "index.json";
const INDEX_TEMP_SUFFIX = ".tmp";

export const generationRecordPath = (
  runId: string,
  depth: number,
  rootDir = "runs",
): string =>
  `${trimTrailingSlash(rootDir)}/${runId}/floors/${depth}/${GENERATION_RECORD_FILE}`;

export const runIndexPath = (runId: string, rootDir = "runs"): string =>
  `${trimTrailingSlash(rootDir)}/${runId}/${INDEX_FILE}`;

const toOutcomeSummary = (
  outcome: GenerationOutcome,
): GenerationOutcomeSummary =>
  outcome.kind === "manifest"
    ? { kind: "manifest" }
    : { kind: "fallback", fallbackId: outcome.fallbackId };

const relativeRunPath = (runDir: string, absolutePath: string): string => {
  const prefix = `${runDir}/`;
  if (!absolutePath.startsWith(prefix)) {
    throw new Error(`path is not under run directory: ${absolutePath}`);
  }
  return absolutePath.slice(prefix.length);
};

const buildProviderSnapshot = (
  providerResult: GenerationAttemptInput["providerResult"],
  manifestPath?: string,
): AttemptProviderSnapshot => {
  if (providerResult.ok) {
    return {
      ok: true,
      usage: providerResult.usage,
      ...(manifestPath === undefined ? {} : { manifestPath }),
    };
  }

  return {
    ok: false,
    usage: providerResult.usage,
    error: providerResult.error,
  };
};

const persistAttemptArtifacts = (
  fs: ArtifactFsAdapter,
  runDir: string,
  floorDir: string,
  attemptIndex: number,
  attempt: GenerationAttemptInput,
): GenerationAttemptRecord => {
  const attemptDir = `${floorDir}/attempts/${attemptIndex}`;
  fs.makeDir(attemptDir);

  const rawOutputPath = `${attemptDir}/raw.txt`;
  const raw =
    attempt.providerResult.ok === true
      ? attempt.providerResult.raw
      : (attempt.providerResult.raw ?? "");
  fs.writeNewFile(rawOutputPath, raw);

  let manifestRelativePath: string | undefined;
  if (attempt.providerResult.ok) {
    const manifestPath = `${attemptDir}/manifest.json`;
    fs.writeNewFile(
      manifestPath,
      `${JSON.stringify(attempt.providerResult.manifest, null, 2)}\n`,
    );
    manifestRelativePath = relativeRunPath(runDir, manifestPath);
  }

  return {
    attemptIndex,
    promptHash: hashPrompt(attempt.prompt),
    rawOutputPath: relativeRunPath(runDir, rawOutputPath),
    provider: buildProviderSnapshot(
      attempt.providerResult,
      manifestRelativePath,
    ),
    ...(attempt.gateReports === undefined
      ? {}
      : { gateReports: attempt.gateReports }),
  };
};

const loadOrCreateIndex = (
  fs: ArtifactFsAdapter,
  runDir: string,
  input: WriteGenerationRecordInput,
): RunGenerationIndex => {
  const indexPath = `${runDir}/${INDEX_FILE}`;
  if (!fs.fileExists(indexPath)) {
    return {
      recordType: "generation-index",
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
      modelId: input.modelId,
      seed: input.seed,
      createdAt: input.createdAt,
      runId: input.runId,
      updatedAt: input.recordedAt,
      floors: [],
    };
  }

  return JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
};

const writeIndexAtomically = (
  fs: ArtifactFsAdapter,
  indexPath: string,
  index: RunGenerationIndex,
): void => {
  const tempPath = `${indexPath}${INDEX_TEMP_SUFFIX}`;
  fs.writeFile(tempPath, `${JSON.stringify(index, null, 2)}\n`);
  fs.rename(tempPath, indexPath);
};

export const writeGenerationRecord = (
  input: WriteGenerationRecordInput,
  options: WriteGenerationRecordOptions = {},
): GenerationRecord => {
  const rootDir = trimTrailingSlash(options.rootDir ?? "runs");
  const fs = options.fs ?? nodeArtifactFsAdapter;
  const runDir = `${rootDir}/${input.runId}`;
  const floorDir = `${runDir}/floors/${input.depth}`;
  const recordPath = `${floorDir}/${GENERATION_RECORD_FILE}`;

  if (fs.fileExists(recordPath)) {
    throw new GenerationRecordExistsError(input.runId, input.depth);
  }

  fs.makeDir(floorDir);

  const attempts = input.attempts.map((attempt, attemptIndex) =>
    persistAttemptArtifacts(fs, runDir, floorDir, attemptIndex, attempt),
  );

  const outcome =
    input.outcome.kind === "manifest"
      ? {
          kind: "manifest" as const,
          manifestPath: relativeRunPath(runDir, input.outcome.manifestPath),
        }
      : input.outcome;

  const record: GenerationRecord = {
    recordType: "generation",
    protocolVersion: PROTOCOL_VERSION,
    engineVersion: ENGINE_VERSION,
    modelId: input.modelId,
    seed: input.seed,
    createdAt: input.createdAt,
    runId: input.runId,
    depth: input.depth,
    attempts,
    outcome,
  };

  fs.writeNewFile(recordPath, `${JSON.stringify(record, null, 2)}\n`);

  const index = loadOrCreateIndex(fs, runDir, input);
  const recordRelativePath = relativeRunPath(runDir, recordPath);
  const floorEntry: FloorIndexEntry = {
    depth: input.depth,
    recordPath: recordRelativePath,
    outcome: toOutcomeSummary(input.outcome),
    recordedAt: input.recordedAt,
  };
  const nextFloors = [
    ...index.floors.filter((entry) => entry.depth !== input.depth),
    floorEntry,
  ].sort((left, right) => left.depth - right.depth);
  const nextIndex: RunGenerationIndex = {
    ...index,
    modelId: input.modelId,
    seed: input.seed,
    updatedAt: input.recordedAt,
    floors: nextFloors,
  };

  writeIndexAtomically(fs, `${runDir}/${INDEX_FILE}`, nextIndex);

  return record;
};

import { validShallowsManifestFixture } from "../../schemas/fixtures/manifest.js";
import type { FloorManifest } from "../../schemas/manifest.js";
import {
  type DirectorProvider,
  type GenerateManifestOptions,
  type JudgeOptions,
  type JudgeResult,
  type JudgeVerdict,
  type ProviderFailureCode,
  type ProviderResult,
  type ProviderTokenUsage,
  type ProviderUsage,
  failure,
} from "./types.js";

export type MockDirectorProviderOptions = {
  readonly manifest?: FloorManifest;
  readonly raw?: string;
  readonly failureMode?: ProviderFailureCode | null;
  readonly judgeVerdict?: JudgeVerdict;
  readonly judgeRaw?: string;
  readonly judgeFailureMode?: ProviderFailureCode | null;
  readonly latencyMs?: number;
  readonly tokens?: ProviderTokenUsage | null;
};

const DEFAULT_JUDGE_VERDICT: JudgeVerdict = {
  verdict: "pass",
  reason: "mock verdict",
  score: 1,
};

export class MockDirectorProvider implements DirectorProvider {
  private readonly manifest: FloorManifest;
  private readonly raw: string;
  private readonly failureMode: ProviderFailureCode | null;
  private readonly judgeVerdict: JudgeVerdict;
  private readonly judgeRaw: string;
  private readonly judgeFailureMode: ProviderFailureCode | null;
  private readonly usage: ProviderUsage;

  constructor(options: MockDirectorProviderOptions = {}) {
    this.manifest = options.manifest ?? validShallowsManifestFixture;
    this.raw = options.raw ?? JSON.stringify(this.manifest);
    this.failureMode = options.failureMode ?? null;
    this.judgeVerdict = options.judgeVerdict ?? DEFAULT_JUDGE_VERDICT;
    this.judgeRaw = options.judgeRaw ?? JSON.stringify(this.judgeVerdict);
    this.judgeFailureMode = options.judgeFailureMode ?? null;
    this.usage = {
      latencyMs: options.latencyMs ?? 0,
      tokens: options.tokens ?? null,
    };
  }

  async generateManifest(
    prompt: string,
    options: GenerateManifestOptions = {},
  ): Promise<ProviderResult> {
    void prompt;
    void options;

    if (this.failureMode !== null) {
      return failure(
        this.failureMode,
        `mock ${this.failureMode}`,
        this.usage,
        this.raw,
      );
    }

    return {
      ok: true,
      raw: this.raw,
      manifest: this.manifest,
      usage: this.usage,
    };
  }

  async judge(prompt: string, options: JudgeOptions = {}): Promise<JudgeResult> {
    void prompt;
    void options;

    if (this.judgeFailureMode !== null) {
      return failure(
        this.judgeFailureMode,
        `mock judge ${this.judgeFailureMode}`,
        this.usage,
        this.judgeRaw,
      );
    }

    return {
      ok: true,
      raw: this.judgeRaw,
      verdict: this.judgeVerdict,
      usage: this.usage,
    };
  }
}

export const createMockDirectorProvider = (
  options: MockDirectorProviderOptions = {},
): MockDirectorProvider => new MockDirectorProvider(options);

import type { DirectorProviderSelection } from "../../config/index.js";
import type {
  FloorManifest,
  ManifestParseError,
} from "../../schemas/manifest.js";

export type DirectorProviderKind = DirectorProviderSelection;

export type ProviderFailureCode =
  | "timeout"
  | "process_error"
  | "parse_fail"
  | "validate_fail";

export type ProviderTokenUsage = {
  readonly inputTokens?: number | null;
  readonly outputTokens?: number | null;
  readonly totalTokens?: number | null;
};

export type ProviderUsage = {
  readonly latencyMs: number;
  readonly tokens?: ProviderTokenUsage | null;
};

export type ProviderError = {
  readonly code: ProviderFailureCode;
  readonly message: string;
  readonly details?: readonly string[];
};

export type ProviderSuccess = {
  readonly ok: true;
  readonly raw: string;
  readonly manifest: FloorManifest;
  readonly usage: ProviderUsage;
};

export type ProviderFailure = {
  readonly ok: false;
  readonly error: ProviderError;
  readonly raw?: string;
  readonly usage: ProviderUsage;
};

export type ProviderResult = ProviderSuccess | ProviderFailure;

export type JudgeVerdictLabel = "pass" | "fail" | "uncertain";

export type JudgeVerdict = {
  readonly verdict: JudgeVerdictLabel;
  readonly reason: string;
  readonly score: number | null;
