});

const wallClockNow = (): number => new Date().getTime();

export const defaultProviderExec: ProviderExec = (
  command,
  args,
) => spawn(command, args, { stdio: ["ignore", "pipe", "pipe"] });

export class AmbientDirectorProvider implements DirectorProvider {
  private readonly exec: ProviderExec;
  private readonly now: ProviderClock;
  private readonly manifestCommand: string;
  private readonly judgeCommand: string;
  private readonly judgeModel: string;
  private readonly manifestTimeoutMs: number;
  private readonly judgeTimeoutMs: number;

  constructor(options: AmbientDirectorProviderOptions = {}) {
    this.exec = options.exec ?? defaultProviderExec;
    this.now = options.now ?? wallClockNow;
    this.manifestCommand =
      options.manifestCommand ?? defaultConfig.director.ambient.manifestCommand;
    this.judgeCommand =
      options.judgeCommand ?? defaultConfig.director.ambient.judgeCommand;
    this.judgeModel =
      options.judgeModel ?? defaultConfig.director.ambient.judgeModel;
    this.manifestTimeoutMs =
      options.manifestTimeoutMs ?? defaultConfig.director.manifestTimeoutMs;
    this.judgeTimeoutMs =
      options.judgeTimeoutMs ?? defaultConfig.director.judgeTimeoutMs;
  }

  async generateManifest(
    prompt: string,
    options: GenerateManifestOptions = {},
  ): Promise<ProviderResult> {
    const result = await runProcess({
      command: this.manifestCommand,
      args: [
        "exec",
        "--sandbox",
        "read-only",
        "-c",
        "approval_policy=never",
        prompt,
      ],
      timeoutMs: options.timeoutMs ?? this.manifestTimeoutMs,
      exec: this.exec,
      now: this.now,
    });

    if (!result.ok) {
      return failure(result.code, result.message, result.usage, result.stdout);
    }

    const parsed = parseManifest(result.stdout);
    if (!parsed.ok) {
      return failure(
        manifestFailureCodeFor(parsed.errors),
        "manifest output did not parse or validate",
        result.usage,
        result.stdout,
        parsed.errors.map((error) => `${error.path}: ${error.message}`),
      );
    }

    return {
      ok: true,
      raw: result.stdout,
      manifest: parsed.manifest,
      usage: result.usage,
    };
  }

  async judge(
    prompt: string,
    options: JudgeOptions = {},
  ): Promise<JudgeResult> {
    const result = await runProcess({
      command: this.judgeCommand,
      args: [
        "--print",
        "--model",
        this.judgeModel,
        buildJudgePrompt(prompt),
      ],
      timeoutMs: options.timeoutMs ?? this.judgeTimeoutMs,
      exec: this.exec,
      now: this.now,
    });

    if (!result.ok) {
      return failure(result.code, result.message, result.usage, result.stdout);
    }

    return parseJudgeResult(result.stdout, result.usage);
  }
}

export const createAmbientDirectorProvider = (
  options: AmbientDirectorProviderOptions = {},
): AmbientDirectorProvider => new AmbientDirectorProvider(options);

const runProcess = ({
  command,
  args,
  timeoutMs,
  exec,
  now,
}: {
  readonly command: string;
  readonly args: readonly string[];
  readonly timeoutMs: number;
  readonly exec: ProviderExec;
  readonly now: ProviderClock;
}): Promise<ProcessRunResult> =>
  new Promise((resolve) => {
    const startedAt = now();
    const stdoutChunks: string[] = [];
    const stderrChunks: string[] = [];
    let settled = false;
    let child: ProviderProcess;

    const usage = (): ProviderUsage => ({
      latencyMs: Math.max(0, now() - startedAt),
      tokens: null,
    });

    const finish = (result: ProcessRunResult): void => {
      if (settled) {
        return;
      }

      settled = true;
      clearTimeout(timeout);
      resolve(result);
    };

    const timeout = setTimeout(() => {
      const stdout = stdoutChunks.join("");
      const stderr = stderrChunks.join("");
      const killed = child.kill("SIGTERM");
      finish({
        ok: false,
        code: "timeout",
        message: `process timed out after ${timeoutMs}ms; killed=${killed}`,
        stdout,
        stderr,
        usage: usage(),
      });
    }, timeoutMs);

    try {
      child = exec(command, args, { stdin: "ignore" });
    } catch (error) {
      finish({
        ok: false,
        code: "process_error",
        message: error instanceof Error ? error.message : String(error),
        stdout: "",
        stderr: "",
        usage: usage(),
      });
      return;
    }

    child.stdout.setEncoding?.("utf8");
    child.stderr.setEncoding?.("utf8");

    child.stdout.on("data", (chunk) => {
      stdoutChunks.push(String(chunk));
    });

    child.stderr.on("data", (chunk) => {
      stderrChunks.push(String(chunk));
    });

    child.on("error", (error) => {
      finish({
        ok: false,
        code: "process_error",
        message: error.message,
        stdout: stdoutChunks.join(""),
        stderr: stderrChunks.join(""),
        usage: usage(),
      });
    });

    child.on("close", (code, signal) => {
      const stdout = stdoutChunks.join("");
      const stderr = stderrChunks.join("");

      if (code === 0) {
        finish({
          ok: true,
          stdout,
          stderr,
          usage: usage(),
        });
        return;
      }

      finish({
        ok: false,

import {
  nodeArtifactFsAdapter,
  trimTrailingSlash,
  type ArtifactFsAdapter,
} from "./fs.js";
import type {
  FloorIndexEntry,
  GenerationRecord,
  RunGenerationIndex,
  RunGenerationSummary,
} from "./types.js";

export type ArtifactReadOptions = {
  readonly rootDir?: string;
  readonly fs?: ArtifactFsAdapter;
};

const INDEX_FILE = "index.json";

const resolveReadContext = (options: ArtifactReadOptions = {}) => ({
  rootDir: trimTrailingSlash(options.rootDir ?? "runs"),
  fs: options.fs ?? nodeArtifactFsAdapter,
});

const loadRunIndexFile = (
  fs: ArtifactFsAdapter,
  rootDir: string,
  runId: string,
): RunGenerationIndex => {
  const indexPath = `${rootDir}/${runId}/${INDEX_FILE}`;
  if (!fs.fileExists(indexPath)) {
    throw new Error(`generation index not found for run: ${runId}`);
  }

  return JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
};

export const listRuns = (
  options: ArtifactReadOptions = {},
): readonly RunGenerationSummary[] => {
  const { rootDir, fs } = resolveReadContext(options);
  if (!fs.isDirectory(rootDir)) {
    return [];
  }

  const summaries: RunGenerationSummary[] = [];

  for (const runId of fs.listEntries(rootDir)) {
    const indexPath = `${rootDir}/${runId}/${INDEX_FILE}`;
    if (!fs.fileExists(indexPath)) {
      continue;
    }

    const index = JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
    if (index.recordType !== "generation-index") {
      continue;
    }

    summaries.push({
      runId: index.runId,
      stamp: {
        recordType: "generation-stamp",
        protocolVersion: index.protocolVersion,
        engineVersion: index.engineVersion,
        modelId: index.modelId,
        seed: index.seed,
        createdAt: index.createdAt,
      },
      updatedAt: index.updatedAt,
      floorCount: index.floors.length,
    });
  }

  return summaries.sort((left, right) =>
    right.updatedAt.localeCompare(left.updatedAt),
  );
};

export const listFloors = (
  runId: string,
  options: ArtifactReadOptions = {},
): readonly FloorIndexEntry[] => {
  const { rootDir, fs } = resolveReadContext(options);
  const index = loadRunIndexFile(fs, rootDir, runId);
  return [...index.floors].sort((left, right) => left.depth - right.depth);
};

export const loadGenerationChain = (
  runId: string,
  depth: number,
  options: ArtifactReadOptions = {},
): GenerationRecord => {
  const { rootDir, fs } = resolveReadContext(options);
  const index = loadRunIndexFile(fs, rootDir, runId);
  const floorEntry = index.floors.find((entry) => entry.depth === depth);
  if (floorEntry === undefined) {
    throw new Error(
      `generation record not indexed for run ${runId} floor ${depth}`,
    );
  }

  const recordPath = `${rootDir}/${runId}/${floorEntry.recordPath}`;
  if (!fs.fileExists(recordPath)) {
    throw new Error(`generation record missing at ${recordPath}`);
  }

  return JSON.parse(fs.readFile(recordPath)) as GenerationRecord;
};

export const readRunIndex = (
  runId: string,
  options: ArtifactReadOptions = {},
): RunGenerationIndex => {
  const { rootDir, fs } = resolveReadContext(options);
  return loadRunIndexFile(fs, rootDir, runId);
};

