import type { RunEvent } from "../../engine/run/events.js";
import type { RunAction } from "../../engine/run/loop.js";
import { PROTOCOL_VERSION } from "../../schemas/protocol.js";
import type {
  ContentRef,
  ParsedTrace,
  TraceHeader,
  TraceTurnRecord
} from "./types.js";

const isRecord = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === "object" && !Array.isArray(value);

const readString = (
  record: Record<string, unknown>,
  key: string,
  label: string
): string => {
  const value = record[key];
  if (typeof value !== "string" || value.length === 0) {
    throw new Error(`${label}.${key} must be a non-empty string`);
  }
  return value;
};

const readNumber = (
  record: Record<string, unknown>,
  key: string,
  label: string
): number => {
  const value = record[key];
  if (typeof value !== "number" || !Number.isInteger(value)) {
    throw new Error(`${label}.${key} must be an integer`);
  }
  return value;
};

const parseContentRef = (value: unknown): ContentRef => {
  if (!isRecord(value)) {
    throw new Error("header.contentRef must be an object");
  }

  return {
    providerId: readString(value, "providerId", "contentRef"),
    packVersion: readString(value, "packVersion", "contentRef")
  };
};

const parseHeader = (value: unknown, lineNumber: number): TraceHeader => {
  if (!isRecord(value)) {
    throw new Error(`line ${lineNumber}: trace header must be a JSON object`);
  }

  if ("turn" in value) {
    throw new Error(`line ${lineNumber}: trace header must not include turn`);
  }

  const recordType = readString(value, "recordType", "header");
  if (recordType !== "header") {
    throw new Error(`header.recordType must be "header"`);
  }

  const protocolVersion = readString(value, "protocolVersion", "header");
  if (protocolVersion !== PROTOCOL_VERSION) {
    throw new Error(`header.protocolVersion must be "${PROTOCOL_VERSION}"`);
  }

  return {
    recordType,
    protocolVersion,
    engineVersion: readString(value, "engineVersion", "header"),
    modelId: readString(value, "modelId", "header"),
    seed: readString(value, "seed", "header"),
    contentRef: parseContentRef(value.contentRef),
    runId: readString(value, "runId", "header"),
    createdAt: readString(value, "createdAt", "header")
  };
};

const parseAction = (value: unknown, lineNumber: number): RunAction => {
  if (!isRecord(value)) {
    throw new Error(`line ${lineNumber}: action must be a JSON object`);
  }

  const kind = value.kind;
  if (typeof kind !== "string" || kind.length === 0) {
    throw new Error(
      `line ${lineNumber}: action.kind must be a non-empty string`
    );
  }

  return value as RunAction;
};

const parseEvents = (
  value: unknown,
  lineNumber: number
): readonly RunEvent[] => {
  if (!Array.isArray(value)) {
    throw new Error(`line ${lineNumber}: events must be an array`);
  }

  return value as readonly RunEvent[];
};

const parseTurnRecord = (
  value: unknown,
  lineNumber: number
): TraceTurnRecord => {
  if (!isRecord(value)) {
    throw new Error(`line ${lineNumber}: trace turn must be a JSON object`);
  }

  if (!("turn" in value)) {
    throw new Error(`line ${lineNumber}: trace turn must include turn`);
  }

  return {
    turn: readNumber(value, "turn", "turn"),
    action: parseAction(value.action, lineNumber),
    events: parseEvents(value.events, lineNumber),
    stateHash: readString(value, "stateHash", "turn")
  };
};

export const parseTraceNdjson = (content: string): ParsedTrace => {
  const lines = content
    .split(/\r?\n/u)
    .map((line) => line.trim())
    .filter((line) => line.length > 0);

  if (lines.length === 0) {
    throw new Error("trace is empty");
  }

  let header: TraceHeader;
  try {
    header = parseHeader(JSON.parse(lines[0] ?? "") as unknown, 1);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`line 1: ${message}`);
  }

  const turns: TraceTurnRecord[] = [];

  for (let index = 1; index < lines.length; index += 1) {
    const lineNumber = index + 1;
    const rawLine = lines[index] ?? "";

    let parsed: unknown;
    try {
      parsed = JSON.parse(rawLine) as unknown;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      throw new Error(`line ${lineNumber}: invalid JSON (${message})`);
    }

    turns.push(parseTurnRecord(parsed, lineNumber));
  }

  return { header, turns };
};

import type { Gate2Evaluation } from "./run.js";

export const GATE2_REASON_CODES = [
  "G2_MATERIALIZATION",
  "G2_CLEAR_RATE",
  "G2_HARD_CLEAR_RATE",
  "G2_HP_RETENTION",
  "G2_DEATH_SHALLOW",
  "G2_ZERO_THREAT",
  "G2_WALL_CLOCK"
] as const;

export type Gate2ReasonCode = (typeof GATE2_REASON_CODES)[number];

export type Gate2Check = {
  readonly code: Gate2ReasonCode;
  readonly pass: boolean;
  readonly detail: string;
  readonly advisory?: true;
};

export type Gate2Verdict = {
  readonly status: "pass" | "reject";
  readonly codes: readonly Gate2ReasonCode[];
};

export type Gate2Report = {
  readonly gate: 2;
  readonly pass: boolean;
  readonly verdict: Gate2Verdict;
  readonly checks: readonly Gate2Check[];
  readonly metrics: Gate2Evaluation["aggregate"];
  readonly candidate: Gate2Evaluation["candidate"];
  readonly ensemble: Gate2Evaluation["ensemble"];
  readonly elapsedMs: number;
  readonly wallClockBudgetMs: number;
};

export const judgeGate2 = (evaluation: Gate2Evaluation): Gate2Report => {
  const threshold = evaluation.thresholds[evaluation.band];
  const hardClearRateMin = threshold.hardRejects.clearRateBelowPercent;
  const deathFloorMax = threshold.hardRejects.anyBotDeathThroughFloor;
  const checks = [
    passCheck("G2_MATERIALIZATION", "candidate floor materialized"),
    checkZeroThreat(evaluation),
    checkDeathShallow(evaluation, deathFloorMax),
    checkHardClearRate(evaluation, hardClearRateMin),
    checkClearRate(evaluation, threshold.clearRateMinPercent),
    checkHpRetention(
      evaluation,
      threshold.medianHpRetentionPercent,
      evaluation.hpRetentionMode
    ),
    checkWallClock(evaluation)
  ];
  const failedBlocking = checks.filter(isBlockingFailure);

  return {
    gate: 2,
    pass: failedBlocking.length === 0,
    verdict: {
      status: failedBlocking.length === 0 ? "pass" : "reject",
      codes: failedBlocking.map((check) => check.code)
    },
    checks,
    metrics: evaluation.aggregate,
    candidate: evaluation.candidate,
    ensemble: evaluation.ensemble,
    elapsedMs: evaluation.elapsedMs,
    wallClockBudgetMs: evaluation.wallClockBudgetMs
  };
};

export const failedGate2Checks = (report: Gate2Report): readonly Gate2Check[] =>
  report.checks.filter((check) => !check.pass);

export const formatGate2Report = (report: Gate2Report): string => {
  const header = `Gate 2: ${report.pass ? "PASS" : "FAIL"}`;
  const lines = report.checks.map(
    (check) =>
      `  [${check.pass ? "ok" : "FAIL"}${check.advisory === true ? " advisory" : ""}] ${check.code}: ${check.detail}`
  );

  return [header, ...lines].join("\n");
};

const checkZeroThreat = (evaluation: Gate2Evaluation): Gate2Check => {
  if (
    evaluation.depth < evaluation.zeroThreatRejectBelowDepth &&
    !evaluation.candidate.hasThreatOnPath
  ) {
    return failCheck(
      "G2_ZERO_THREAT",
      `depth ${evaluation.depth} has no enemy encounter possible on the stairs path`
    );
  }

  return passCheck(
    "G2_ZERO_THREAT",
    evaluation.depth < evaluation.zeroThreatRejectBelowDepth
      ? "at least one enemy encounter is possible on the stairs path"
      : `zero-threat hard reject applies only below depth ${evaluation.zeroThreatRejectBelowDepth}`
  );
};

const checkDeathShallow = (
  evaluation: Gate2Evaluation,
  deathFloorMax: number | undefined
): Gate2Check => {
  if (
    deathFloorMax !== undefined &&
    evaluation.depth <= deathFloorMax &&
    evaluation.aggregate.deathCount > 0
  ) {
    return failCheck(
      "G2_DEATH_SHALLOW",
      `${evaluation.aggregate.deathCount} bot death(s) on depth ${evaluation.depth}`
    );
  }

  return passCheck(
    "G2_DEATH_SHALLOW",
    deathFloorMax === undefined
      ? "band has no shallow-death hard reject"
      : `${evaluation.aggregate.deathCount} bot death(s) through floor ${deathFloorMax}`
  );
};

const checkHardClearRate = (
  evaluation: Gate2Evaluation,
  hardClearRateMin: number | undefined
): Gate2Check => {
  if (
    hardClearRateMin !== undefined &&
    evaluation.aggregate.clearRatePercent < hardClearRateMin
  ) {
    return failCheck(
      "G2_HARD_CLEAR_RATE",
      `clear rate ${formatPercent(evaluation.aggregate.clearRatePercent)} is below hard reject ${hardClearRateMin}%`
    );
  }

  return passCheck(
    "G2_HARD_CLEAR_RATE",
    hardClearRateMin === undefined
      ? "band has no hard clear-rate floor"
      : `clear rate ${formatPercent(evaluation.aggregate.clearRatePercent)} is at least hard reject ${hardClearRateMin}%`
  );
};

const checkClearRate = (
  evaluation: Gate2Evaluation,
  clearRateMin: number
): Gate2Check => {
  if (evaluation.aggregate.clearRatePercent < clearRateMin) {
    return failCheck(
      "G2_CLEAR_RATE",
      `clear rate ${formatPercent(evaluation.aggregate.clearRatePercent)} is below ${clearRateMin}%`
    );
  }

  return passCheck(
    "G2_CLEAR_RATE",
    `clear rate ${formatPercent(evaluation.aggregate.clearRatePercent)} is at least ${clearRateMin}%`
  );
};

const checkHpRetention = (
  evaluation: Gate2Evaluation,
  band: { readonly min: number; readonly max: number },
  mode: Gate2Evaluation["hpRetentionMode"]
): Gate2Check => {
  const hp = evaluation.aggregate.medianHpRetentionPercent;
  const advisory = mode === "advisory";

  if (hp < band.min || hp > band.max) {
    return failCheck(
      "G2_HP_RETENTION",
      `median HP retention ${formatPercent(hp)} is outside ${band.min}-${band.max}%`,
      advisory
    );
  }

  return passCheck(
    "G2_HP_RETENTION",
    `median HP retention ${formatPercent(hp)} is inside ${band.min}-${band.max}%`,
    advisory
  );
};

const checkWallClock = (evaluation: Gate2Evaluation): Gate2Check => {
  if (evaluation.elapsedMs > evaluation.wallClockBudgetMs) {
    return failCheck(
      "G2_WALL_CLOCK",
      `ensemble took ${evaluation.elapsedMs}ms over budget ${evaluation.wallClockBudgetMs}ms`
    );
  }

  return passCheck(
    "G2_WALL_CLOCK",
    `ensemble took ${evaluation.elapsedMs}ms within budget ${evaluation.wallClockBudgetMs}ms`
  );
};

const passCheck = (
  code: Gate2ReasonCode,
  detail: string,
  advisory = false
): Gate2Check => ({
  code,
  pass: true,
  detail,
  ...(advisory ? { advisory: true as const } : {})
});

const failCheck = (
  code: Gate2ReasonCode,
  detail: string,
  advisory = false
): Gate2Check => ({
  code,
  pass: false,
  detail,
  ...(advisory ? { advisory: true as const } : {})
});

const isBlockingFailure = (check: Gate2Check): boolean =>
  !check.pass && check.advisory !== true;

const formatPercent = (value: number): string => {
  if (Number.isInteger(value)) {
    return `${value}%`;
  }

  return `${value.toFixed(1)}%`;
};

