export type InputSource = {
  readonly readKey: () => Promise<string | null>;
  readonly close: () => void;
};

export const createScriptedInputSource = (script: string): InputSource => {
  const keys = [...expandScript(script)];
  let index = 0;

  return {
    readKey: async () => {
      if (index >= keys.length) {
        return null;
      }

      const key = keys[index];
      index += 1;
      return key ?? null;
    },
    close: () => {},
  };
};

export const createTerminalInputSource = (): InputSource => {
  if (!process.stdin.isTTY) {
    return createScriptedInputSource("");
  }

  const stdin = process.stdin;
  stdin.setRawMode(true);
  stdin.resume();
  stdin.setEncoding("utf8");

  const queue: string[] = [];
  const waiters: Array<(key: string | null) => void> = [];
  let closed = false;

  const flush = (): void => {
    while (queue.length > 0 && waiters.length > 0) {
      const key = queue.shift();
      const resolve = waiters.shift();
      resolve?.(key ?? null);
    }
  };

  const onData = (chunk: string): void => {
    for (const key of chunkKeys(chunk)) {
      queue.push(key);
    }
    flush();
  };

  stdin.on("data", onData);

  return {
    readKey: () =>
      new Promise((resolve) => {
        if (closed) {
          resolve(null);
          return;
        }

        if (queue.length > 0) {
          resolve(queue.shift() ?? null);
          return;
        }

        waiters.push(resolve);
      }),
    close: () => {
      if (closed) {
        return;
      }

      closed = true;
      stdin.off("data", onData);
      stdin.setRawMode(false);
      stdin.pause();

      for (const resolve of waiters.splice(0)) {
        resolve(null);
      }
    },
  };
};

export const createLineInputSource = (lines: readonly string[]): InputSource => {
  const rl: Interface = createInterface({
    input: process.stdin,
    output: process.stdout,
    terminal: false,
  });
  const queue = [...lines];
  let closed = false;

  return {
    readKey: () =>
      new Promise((resolve) => {
        if (closed) {
          resolve(null);
          return;
        }

        if (queue.length === 0) {
          closed = true;
          rl.close();
          resolve(null);
          return;
        }

        const line = queue.shift();
        if (line === undefined) {
          resolve(null);
          return;
        }

        resolve(line.length === 0 ? "\r" : line[0] ?? null);
      }),
    close: () => {
      if (!closed) {
        closed = true;
        rl.close();
      }
    },
  };
};

export const chunkKeys = (chunk: string): string[] => {
  const keys: string[] = [];

  for (let index = 0; index < chunk.length; index += 1) {
    const char = chunk[index];

    if (char === "\u001b" && chunk[index + 1] === undefined) {
      keys.push("Escape");
      continue;
    }

    if (char === "\u001b" && chunk[index + 1] === "[") {
      const code = chunk[index + 2];
      if (code === "A") {
        keys.push("ArrowUp");
        index += 2;
        continue;
      }
      if (code === "B") {
        keys.push("ArrowDown");
        index += 2;
        continue;
      }

